## 2. C / C++ stub file (`pcapng_stubs.c`)

> **Important** – the stub file must be compiled as **C++** (e.g. `g++ -c
> pcapng_stubs.c -I$(OCAML_INCLUDE_DIR) -fPIC`).  
> The file is named `*.c` only because OCaml’s build tools expect that
> extension; the `extern "C"` wrappers guarantee a C ABI.

```c
/*--------------------------------------------------------------------
   pcapng_stubs.c – C/C++ glue for the libpcapng OCaml binding
  --------------------------------------------------------------------*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <iostream>
#include <exception>
#include <memory>
#include <vector>
#include <chrono>

/* -----------------------------------------------------------------
   The (hypothetical) C++ library we are binding to.
   ----------------------------------------------------------------- */
namespace pcapng {

/* A simple representation of a captured frame.  Real libpcapng
   would expose many more fields – we keep only a few for the demo. */
struct Frame {
    std::vector<uint8_t> data;          // packet bytes
    std::chrono::system_clock::time_point ts; // timestamp
    Frame(std::vector<uint8_t> d,
          std::chrono::system_clock::time_point t)
        : data(std::move(d)), ts(t) {}
};

/* Parser that owns a vector of Frames and provides an iterator. */
class Parser {
public:
    explicit Parser(const std::string& filename) {
        /* In a real binding this would call libpcapng to read the file.
           Here we fake a few frames just for illustration. */
        if (filename.empty())
            throw std::runtime_error("empty filename");

        // fake data: three frames with increasing timestamps
        for (int i = 0; i < 3; ++i) {
            std::vector<uint8_t> pkt(60 + i, uint8_t(0x42 + i));
            auto ts = std::chrono::system_clock::now()
                      + std::chrono::seconds(i);
            frames_.emplace_back(std::move(pkt), ts);
        }
        it_ = frames_.begin();
    }

    ~Parser() = default;

    /* Return the next frame or nullptr if we are at the end. */
    const Frame* next() {
        if (it_ == frames_.end())
            return nullptr;
        const Frame* f = &*it_;
        ++it_;
        return f;
    }

    /* Reset iterator – useful for repeated `iter` calls. */
    void reset() { it_ = frames_.begin(); }

private:
    std::vector<Frame> frames_;
    std::vector<Frame>::iterator it_;
};

} // namespace pcapng

/* -----------------------------------------------------------------
   OCaml custom blocks for the two opaque types.
   ----------------------------------------------------------------- */
static struct custom_operations parser_ops = {
    "pcapng.parser",
    custom_finalize_default,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

static struct custom_operations frame_ops = {
    "pcapng.frame",
    custom_finalize_default,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

static inline pcapng::Parser* parser_val(value v) {
    return *(pcapng::Parser **) Data_custom_val(v);
}
static inline void parser_set(value v, pcapng::Parser* p) {
    *(pcapng::Parser **) Data_custom_val(v) = p;
}

static inline const pcapng::Frame* frame_val(value v) {
    return *(const pcapng::Frame **) Data_custom_val(v);
}
static inline void frame_set(value v, const pcapng::Frame* f) {
    *(const pcapng::Frame **) Data_custom_val(v) = f;
}

/* -----------------------------------------------------------------
   Helper to raise a generic Failure with a formatted message.
   ----------------------------------------------------------------- */
static void raise_failure(const char* fmt, const std::string& arg) {
    char buf[256];
    snprintf(buf, sizeof(buf), fmt, arg.c_str());
    caml_failwith(buf);
}

/* -----------------------------------------------------------------
   OCaml primitives
   ----------------------------------------------------------------- */

/* val open_file : string -> parser */
CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_parser);
    const char* path = String_val(v_path);
    try {
        std::unique_ptr<pcapng::Parser> p(new pcapng::Parser(path));
        v_parser = caml_alloc_custom(&parser_ops, sizeof(pcapng::Parser*), 0, 1);
        parser_set(v_parser, p.release());          // transfer ownership
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
    CAMLreturn(v_parser);
}

/* val close : parser -> unit */
CAMLprim value caml_pcapng_close(value v_parser) {
    CAMLparam1(v_parser);
    pcapng::Parser* p = parser_val(v_parser);
    delete p;                                      // free the C++ object
    /* Overwrite the pointer so that a later use crashes early */
    parser_set(v_parser, nullptr);
    CAMLreturn(Val_unit);
}

/* val next : parser -> frame option */
CAMLprim value caml_pcapng_next(value v_parser) {
    CAMLparam1(v_parser);
    CAMLlocal2(v_some, v_frame);
    pcapng::Parser* p = parser_val(v_parser);
    if (!p) caml_failwith("Parser already closed");
    const pcapng::Frame* f = p->next();
    if (f == nullptr) {
        CAMLreturn(Val_int(0)); /* None = 0 */
    }
    v_frame = caml_alloc_custom(&frame_ops, sizeof(const pcapng::Frame*), 0, 1);
    frame_set(v_frame, f);
    v_some = caml_alloc(1, 0);                     /* Some */
    Store_field(v_some, 0, v_frame);
    CAMLreturn(v_some);
}

/* val iter : parser -> (frame -> unit) -> unit */
CAMLprim value caml_pcapng_iter(value v_parser, value v_fun) {
    CAMLparam2(v_parser, v_fun);
    pcapng::Parser* p = parser_val(v_parser);
    if (!p) caml_failwith("Parser already closed");
    /* Reset iterator so that repeated calls to `iter` start from the beginning */
    p->reset();

    /* The callback may allocate OCaml values, so we must release the OCaml
       runtime lock while iterating over the C++ frames.  This allows other
       OCaml threads to run. */
    caml_release_runtime_system();

    while (true) {
        const pcapng::Frame* f = p->next();
        if (!f) break;

        /* Build a temporary OCaml frame value.  It is a custom block that
           merely points to the C++ frame; the C++ frame lives as long as the
           parser, so it is safe to expose it. */
        value v_frame = caml_alloc_custom(&frame_ops,
                                          sizeof(const pcapng::Frame*), 0, 1);
        frame_set(v_frame, f);

        caml_acquire_runtime_system();   /* reacquire before calling back */
        caml_callback(v_fun, v_frame);
        caml_release_runtime_system();   /* back to iteration */
    }

    caml_acquire_runtime_system();       /* final reacquire */
    CAMLreturn(Val_unit);
}

/* val data : frame -> bytes */
CAMLprim value caml_pcapng_frame_data(value v_frame) {
    CAMLparam1(v_frame);
    CAMLlocal1(v_bytes);
    const pcapng::Frame* f = frame_val(v_frame);
    if (!f) caml_failwith("Invalid frame (null)");
    /* Allocate a fresh OCaml bytes block and copy the payload */
    v_bytes = caml_alloc_initialized_string(f->data.size(),
                                            (char*)f->data.data());
    CAMLreturn(v_bytes);
}

/* val length : frame -> int */
CAMLprim value caml_pcapng_frame_length(value v_frame) {
    CAMLparam1(v_frame);
    const pcapng::Frame* f = frame_val(v_frame);
    CAMLreturn(Val_int((int)f->data.size()));
}

/* val timestamp : frame -> float */
CAMLprim value caml_pcapng_frame_timestamp(value v_frame) {
    CAMLparam1(v_frame);
    const pcapng::Frame* f = frame_val(v_frame);
    using namespace std::chrono;
    double secs = duration<double>(f->ts.time_since_epoch()).count();
    CAMLreturn(caml_copy_double(secs));
}

/* -----------------------------------------------------------------
   Optional convenience wrapper: `with_file` implemented in OCaml.
   ----------------------------------------------------------------- */
```

