## 3. How to compile the binding

```sh
# Assume the files are in the current directory.
# OCaml's include dir (replace with your actual path if needed)
OCAML_INC=$(ocamlc -where)

# Compile the stub as C++ (produces pcapng_stubs.o)
g++ -c -O2 -Wall -fPIC -I$OCAML_INC pcapng_stubs.c -o pcapng_stubs.o

# Compile the OCaml interface (no implementation file needed)
ocamlc -c pcapng.mli   # generates pcapng.cmi

# Build a library (static for simplicity)
ocamlc -a -o pcapng.cma pcapng.cmi pcapng_stubs.o

# (Optional) build a tiny test program
cat > test.ml <<'EOF'
#use "topfind";;
#require "pcapng";;

let () =
  let parser = Pcapng.open_file "sample.pcapng" in
  Printf.printf "Iterating with a closure …\n";
  Pcapng.iter parser (fun frm ->
      Printf.printf "  frame %d bytes @ %f\n"
        (Pcapng.length frm) (Pcapng.timestamp frm));
  Pcapng.close parser
EOF

ocamlc -I . -o test.exe pcapng.cma test.ml
./test.exe
```

(Replace `sample.pcapng` with a real file if you link against the real libpcapng.)

